import anthropic

client = anthropic.Anthropic()

response = client.messages.create(
    model="claude-sonnet-4-6",   # or claude-opus-4-8 for hardest tasks
    max_tokens=16000,
    thinking={
        "type": "enabled",
        "budget_tokens": 10000,  # how many tokens to allocate for reasoning
    },
    messages=[{
        "role": "user",
        "content": "Prove that there are infinitely many prime numbers.",
    }],
)

# Response contains both thinking blocks and text blocks
for block in response.content:
    if block.type == "thinking":
        print("=== REASONING ===")
        print(block.thinking[:500], "...")   # internal scratchpad
    elif block.type == "text":
        print("=== ANSWER ===")
        print(block.text)

def reasoning_debug(prompt: str, expected_answer: str | None = None) -> dict:
    """
    Run a prompt with extended thinking and return a structured debug record.
    """
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=20000,
        thinking={"type": "enabled", "budget_tokens": 10000},
        messages=[{"role": "user", "content": prompt}],
    )

    thinking_text = ""
    answer_text = ""
    for block in response.content:
        if block.type == "thinking":
            thinking_text = block.thinking
        elif block.type == "text":
            answer_text = block.text

    correct = None
    if expected_answer is not None:
        correct = expected_answer.lower().strip() in answer_text.lower()

    return {
        "prompt": prompt,
        "answer": answer_text,
        "thinking_length": len(thinking_text),
        "thinking_preview": thinking_text[:300],
        "correct": correct,
        "usage": {
            "input_tokens": response.usage.input_tokens,
            "output_tokens": response.usage.output_tokens,
        },
    }

def stream_with_thinking(prompt: str, budget: int = 8000) -> str:
    """Stream a reasoning response, showing a progress indicator for thinking."""
    final_text = []
    thinking_token_count = 0

    with client.messages.stream(
        model="claude-sonnet-4-6",
        max_tokens=budget + 2000,
        thinking={"type": "enabled", "budget_tokens": budget},
        messages=[{"role": "user", "content": prompt}],
    ) as stream:
        current_block_type = None
        for event in stream:
            event_type = type(event).__name__

            if event_type == "ContentBlockStart":
                block = event.content_block
                current_block_type = block.type
                if block.type == "thinking":
                    print("\r[Reasoning...]", end="", flush=True)

            elif event_type == "ContentBlockDelta":
                delta = event.delta
                if current_block_type == "thinking" and hasattr(delta, "thinking"):
                    thinking_token_count += len(delta.thinking.split())
                    print(f"\r[Reasoning... ~{thinking_token_count} tokens]", end="", flush=True)
                elif current_block_type == "text" and hasattr(delta, "text"):
                    final_text.append(delta.text)

            elif event_type == "ContentBlockStop":
                if current_block_type == "thinking":
                    print()  # newline after thinking progress indicator

    return "".join(final_text)
